def k_means_clustering(points: list[tuple[float, ...]], k: int, initial_centroids: list[tuple[float, ...]], max_iterations: int) -> list[tuple[float, ...]]:
    def euclidean_distance(a, b):
        return sum((x - y) ** 2 for x, y in zip(a, b)) ** 0.5

    def compute_centroid(cluster):
        n = len(cluster)
        dim = len(cluster[0])
        return tuple(sum(p[d] for p in cluster) / n for d in range(dim))

    centroids = list(initial_centroids)

    for _ in range(max_iterations):
        # Assignment step: assign each point to nearest centroid
        clusters = [[] for _ in range(k)]
        for point in points:
            distances = [euclidean_distance(point, c) for c in centroids]
            nearest = distances.index(min(distances))
            clusters[nearest].append(point)

        # Update step: recompute centroids
        new_centroids = []
        for i, cluster in enumerate(clusters):
            if cluster:
                new_centroids.append(compute_centroid(cluster))
            else:
                new_centroids.append(centroids[i])  # keep old centroid if cluster is empty

        # Convergence check
        if new_centroids == centroids:
            break

        centroids = new_centroids

    return [tuple(round(c, 4) for c in centroid) for centroid in centroids]
